input.script:
import { executionsClient } from "@dynatrace-sdk/client-automation";

export default async function main({ execution_id }) {

  // Obtener el contexto de ejecucion via SDK para acceder al problema del trigger
  let execution;
  try {
    execution = await executionsClient.getExecution({ id: execution_id });
  } catch (e) {
    throw new Error(`[EDA-Problem-Integration] No se pudo obtener la ejecucion ${execution_id}: ${e.message}`);
  }

  const event = execution.params?.event;

  // Validar campos requeridos antes de continuar
  const requiredFields = ["event.id", "event.name", "event.category"];
  const missing = requiredFields.filter(f => event?.[f] == null || event?.[f] === "");
  if (!event || missing.length > 0) {
    throw new Error(`[EDA-Problem-Integration] Campos requeridos ausentes en el problema: ${missing.join(", ")}`);
  }

  // Extraer tag especifico del array entity_tags
  const tags = event["entity_tags"] || [];
  const getTag = (prefix) => {
    const p = prefix.toUpperCase();
    const match = tags.find(t => t.toUpperCase().startsWith(p + ":"));
    return match ? match.split(":").slice(1).join(":") : null;
  };

  const toISO = (ts) => {
    if (!ts) return null;
    const ms = ts < 1e12 ? ts * 1000 : ts;
    return new Date(ms).toISOString();
  };

  // A nivel de problema, Dynatrace devuelve varios campos de entidad como
  // array aunque haya un unico valor (dt.entity.host, dt.host_group.id,
  // dt.davis.impact_level). Validado contra 5 problemas reales el 2026-06-30.
  const first = (v) => Array.isArray(v) ? (v[0] ?? null) : (v ?? null);

  return {
      // Identificacion del problema
      event_id:             event["event.id"],
      display_id:           event["display_id"] || null,
      correlation_id:       event["dt.event.correlation_id"] || null,

      // Que paso
      event_name:           event["event.name"],
      event_description:    event["event.description"] || null,
      event_category:       event["event.category"],
      event_severity:       event["event.severity"] ?? null,
      event_status:         event["event.status"] || null,
      status_transition:    event["event.status_transition"] || null,
      event_start:          toISO(event["event.start"]),
      event_end:            toISO(event["event.end"]),

      // Donde paso
      // root_cause_entity_id/name: en los 5 problemas reales analizados siempre
      // vinieron null (incluido un caso de servicio JBoss) - Davis no siempre
      // resuelve una causa raiz unica. No depender de estos campos.
      root_cause_entity_id:    event["root_cause_entity_id"] || null,
      root_cause_entity_name:  event["root_cause_entity_name"] || null,
      // Entidad afectada principal: dato fiable para ubicar que remediar,
      // funciona igual si la entidad es un host o un service (ej. JBoss/httpd).
      affected_entity_id:      first(event["affected_entity_ids"]),
      affected_entity_name:    first(event["affected_entity_names"]),
      affected_entity_type:    first(event["affected_entity_types"]),
      affected_entity_ids:     event["affected_entity_ids"] || [],
      affected_entity_names:   event["affected_entity_names"] || [],
      affected_entity_types:   event["affected_entity_types"] || [],
      // host_id/host_name solo se completan cuando la entidad afectada es un
      // host; en problemas a nivel service (ej. JBoss) quedan null - usar
      // affected_entity_* arriba.
      host_id:              first(event["dt.entity.host"]),
      host_name:            event["dt.entity.host.name"] || event["host.name"] || null,
      host_group_id:        first(event["dt.host_group.id"]),
      host_group_name:      event["dt.entity.host_group.name"] || null,
      source_entity_type:   event["dt.source_entity.type"] || null,
      source_entity:        event["dt.source_entity"] || null,

      // Enrutamiento y contexto operacional (extraido de entity_tags)
      environment:          getTag("ENVIRONMENT"),
      opco:                 getTag("AGO_AXAOPCOTRIGRAM"),
      assignment_group:     getTag("AGO_DEFAULT_ASSIGNMENT_GROUP"),
      platform:             getTag("AGO_AXAPLATFORM"),
      app:                  getTag("AGO_GLOBAL_APP"),
      app_service_id:       getTag("AGO_GLOBAL_APPSERVICEID"),
      patch_environment:    getTag("AGO_AXAPATCHENVIRONMENT"),

      // Control de remediacion
      // dt.davis.timeout vino siempre null a nivel de problema en los datos
      // reales analizados (si existe, es un campo de evento individual).
      timeout_minutes:      first(event["dt.davis.timeout"]),
      impact_level:         first(event["dt.davis.impact_level"]),
      mute_status:          event["dt.davis.mute.status"] || null,

      // Trazabilidad hacia Dynatrace (eventos Davis que componen el problema)
      underlying_event_ids: event["dt.davis.event_ids"] || []
    };
}
